// Accept lesson_id from parent workflow (W_Master) via Execute Workflow Trigger.
// Manual Trigger has no payload — lesson_id stays null and Code nodes downstream
// skip the lesson_id filter (operate on ALL segments — backward-compatible legacy behavior).
const incoming = $input.first()?.json || {};
const lesson_id = incoming.lesson_id || null;
return [{ json: { lesson_id } }];

const lesson_id = $('Get Params').first().json.lesson_id;
const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const activeLangs        = (configMap.active_langs || 'de,es,fr,it,pl,pt,tr').split(',').map(s => s.trim());
const MIN_GAP            = parseFloat(configMap.min_inter_segment_gap_sec)  || 0.4;
const MAX_BORROW         = parseFloat(configMap.max_borrow_per_segment_sec) || 2.0;
const EXPANSION_THRESHOLD= parseFloat(configMap.expansion_threshold)        || 0.85;
const SILENCE_LEAD_RATIO = parseFloat(configMap.silence_lead_ratio)         || 0.2;
const SILENCE_LEAD_MAX_SEC = parseFloat(configMap.silence_lead_max_sec)    || 0.05;

const voiceMap = {};
$('Read Voices').all().forEach(i => { if (i.json.lang) voiceMap[i.json.lang] = i.json; });

const sortedSegs = $input.all()
  .filter(i => i.json.segment_id)
  .filter(i => !lesson_id || i.json.segment_id.startsWith(lesson_id + '_'))
  .sort((a, b) => (parseFloat(a.json.en_start_sec) || 0) - (parseFloat(b.json.en_start_sec) || 0));
if (sortedSegs.length === 0) throw new Error('No segments to synthesize' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));

const slotInfo = {};
for (let i = 0; i < sortedSegs.length; i++) {
  const seg     = sortedSegs[i].json;
  const prevEnd = i > 0 ? (parseFloat(sortedSegs[i-1].json.en_end_sec) || 0) : 0;
  const start   = parseFloat(seg.en_start_sec)    || 0;
  const end     = parseFloat(seg.en_end_sec)      || 0;
  // Authoritative slot duration: end - start. Stored en_duration_sec can be
  // corrupted in segments tab (root cause TBD); prefer computed value.
  const storedDur = parseFloat(seg.en_duration_sec) || 0;
  const computedDur = Math.max(0, end - start);
  const dur = computedDur > 0 ? computedDur : storedDur;
  if (computedDur > 0 && storedDur > 0 && Math.abs(computedDur - storedDur) > 0.5) {
    console.warn(`W3 Expand TTS Jobs: segment ${seg.segment_id} stored en_duration_sec=${storedDur.toFixed(3)} disagrees with (end-start)=${computedDur.toFixed(3)}. Using computed.`);
  }

  const isLast = (i === sortedSegs.length - 1);
  const nextStart = isLast ? end : (parseFloat(sortedSegs[i+1].json.en_start_sec) || 0);
  const gapAfter = Math.max(0, nextStart - end);

  // Unified signed adjustment: negative = steal needed; positive = borrow available
  const signedAdj      = gapAfter - MIN_GAP;
  const trailingSteal  = signedAdj < 0 ? -signedAdj : 0;
  const maxBorrowable  = isLast ? 0 : Math.max(0, Math.min(signedAdj, MAX_BORROW));

  // Audio budget WITHOUT borrow (steal already accounted)
  const ttsBudget      = Math.max(dur * 0.5, dur - trailingSteal);
  // Effective slot WITH borrow allowance
  const effectiveSlot  = ttsBudget + maxBorrowable;

  slotInfo[seg.segment_id] = {
    slot_start_sec:           prevEnd,
    slot_end_sec:             end,
    lead_silence_natural_sec: Math.max(0, start - prevEnd),
    tts_budget_sec:           parseFloat(ttsBudget.toFixed(3)),
    effective_slot_sec:       parseFloat(effectiveSlot.toFixed(3)),
    max_borrowable_sec:       parseFloat(maxBorrowable.toFixed(3)),
    trailing_steal_sec:       parseFloat(trailingSteal.toFixed(3)),
    gap_after_sec:            parseFloat(gapAfter.toFixed(3)),
  };
}

const results = [];
for (const item of sortedSegs) {
  const seg = item.json;
  // Re-derive dur authoritatively for result row (same logic as slotInfo loop).
  const _segEnd   = parseFloat(seg.en_end_sec)   || 0;
  const _segStart = parseFloat(seg.en_start_sec) || 0;
  const _segDur   = Math.max(0, _segEnd - _segStart) || (parseFloat(seg.en_duration_sec) || 0);
  for (const lang of activeLangs) {
    const text = seg[`${lang}_text`];
    if (!text || !text.trim()) continue;
    const voice = voiceMap[lang] || {};
    if (!voice.voice_id) continue;
    const info = slotInfo[seg.segment_id] || {};
    results.push({ json: {
      segment_id:               seg.segment_id,
      lesson_id:                seg.lesson_id || 'unknown',
      lang,
      text,
      en_text:                  seg.en_text || '',
      en_duration_sec:          _segDur,
      en_start_sec:             parseFloat(seg.en_start_sec) || 0,
      en_end_sec:               parseFloat(seg.en_end_sec) || 0,
      slot_start_sec:           info.slot_start_sec           || 0,
      slot_end_sec:             info.slot_end_sec             || 0,
      lead_silence_natural_sec: info.lead_silence_natural_sec || 0,
      tts_budget_sec:           info.tts_budget_sec           || (parseFloat(seg.en_duration_sec) || 0),
      effective_slot_sec:       info.effective_slot_sec       || (parseFloat(seg.en_duration_sec) || 0),
      max_borrowable_sec:       info.max_borrowable_sec       || 0,
      trailing_steal_sec:       info.trailing_steal_sec       || 0,
      gap_after_sec:            info.gap_after_sec            || 0,
      silence_lead_ratio:       SILENCE_LEAD_RATIO,
      silence_lead_max_sec:     SILENCE_LEAD_MAX_SEC,
      expansion_threshold:      EXPANSION_THRESHOLD,
      voice_id:                 voice.voice_id,
      stability:                parseFloat(voice.stability)         || 0.5,
      similarity_boost:         parseFloat(voice.similarity_boost)  || 0.75,
      style:                    parseFloat(voice.style)             || 0,
      speed:                    parseFloat(voice.speed)             || 1.0,
      model:                    voice.model || 'eleven_multilingual_v2',
    }});
  }
}
return results;

const SAMPLE_RATE          = 22050;
const BPS                  = 2;
const BUDGET_FACTOR        = 1.05;
const MIN_RETAIN           = 0.60;
const MAX_RETAIN_EXPANSION = 1.5;
// Per-language CPS — defaults tuned against real ElevenLabs output; overridable via
// config keys cps_estimate_de, cps_estimate_es, …, cps_estimate_tr. Computed below.
const CPS_DEFAULTS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };
const HAIKU_MODEL          = 'claude-haiku-4-5-20251001';

const job = $('Expand TTS Jobs').item.json;
const {
  voice_id, en_text, en_duration_sec,
  lead_silence_natural_sec, tts_budget_sec, effective_slot_sec, trailing_steal_sec,
  silence_lead_ratio, silence_lead_max_sec, expansion_threshold,
  stability, similarity_boost, segment_id, lang, lesson_id,
} = job;

const enDur        = parseFloat(en_duration_sec)          || 0;
const naturalLead  = parseFloat(lead_silence_natural_sec) || 0;
const budget       = parseFloat(tts_budget_sec)           || enDur;
const slot         = parseFloat(effective_slot_sec)       || budget;
const trailSteal   = parseFloat(trailing_steal_sec)       || 0;
const leadRatio    = parseFloat(silence_lead_ratio)       || 0.2;
const leadMaxSec   = parseFloat(silence_lead_max_sec)    || 0.05;
const expThreshold = parseFloat(expansion_threshold)      || 0.75;
const enRef        = en_text || '';

const maxBorrowable = Math.max(0, slot - budget);
// Conditional breath-borrow: maxAllowed computed below after configMap is built (needs short_seg_threshold_sec).

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const EL_KEY  = configMap.elevenlabs_api_key  || '';
const ANT_KEY = configMap.anthropic_api_key   || '';
// Externalized-prompts loader. Reads from the "prompts" Google Sheets tab via
// upstream Read Prompts node. Throws if a required key is missing (fail-fast).
// Placeholders use {{var}} syntax; vars object replaces them at load time.
const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });
function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}
const TOV     = loadPrompt('tone_of_voice');

// Resolve per-language CPS from config (defaults from CPS_DEFAULTS above).
const LANG_CPS = {
  de: parseFloat(configMap.cps_estimate_de) || CPS_DEFAULTS.de,
  es: parseFloat(configMap.cps_estimate_es) || CPS_DEFAULTS.es,
  fr: parseFloat(configMap.cps_estimate_fr) || CPS_DEFAULTS.fr,
  pl: parseFloat(configMap.cps_estimate_pl) || CPS_DEFAULTS.pl,
  pt: parseFloat(configMap.cps_estimate_pt) || CPS_DEFAULTS.pt,
  it: parseFloat(configMap.cps_estimate_it) || CPS_DEFAULTS.it,
  tr: parseFloat(configMap.cps_estimate_tr) || CPS_DEFAULTS.tr,
};
if (!EL_KEY)  throw new Error('elevenlabs_api_key missing from config sheet');
if (!ANT_KEY) throw new Error('anthropic_api_key missing from config sheet');

// Conditional breath-borrow: only short segments (< SHORT_SEG_THRESHOLD) with available
// trailing silence (slot > enDur) may extend past en_duration into the gap. Bounded by
// effective_slot_sec (= en_duration + maxBorrowable). Normal-length segments stay strict.
// Set short_seg_threshold_sec=0 in config to fully disable (revert to strict alignment).
const SHORT_SEG_THRESHOLD = parseFloat(configMap.short_seg_threshold_sec) || 2.0;
const isShortSeg          = enDur > 0 && enDur < SHORT_SEG_THRESHOLD && slot > enDur;
const maxAllowed          = isShortSeg ? slot : enDur;

const inputItem = $input.first();
const binaryData = inputItem.binary?.data;

// Capture diagnostic snapshot for the warning field — visible in n8n Output
// panel without needing log-level visibility. Used only on TTS failure.
const failureDiag = {
  hasBinarySlot:     !!inputItem.binary,
  hasBinaryDataObj:  !!binaryData,
  binaryDataKeys:    binaryData ? Object.keys(binaryData) : [],
  binaryMimeType:    binaryData?.mimeType || null,
  binaryFileName:    binaryData?.fileName || null,
  binaryFileSize:    binaryData?.fileSize || null,
  binaryDataId:      binaryData?.id || null,
  pcmBytes:          0,
  bufferLoadError:   null,
  contentPreview:    null,
};

// CRITICAL: must use this.helpers.getBinaryDataBuffer() — NOT Buffer.from(binary.data.data).
// With N8N_BINARY_DATA_MODE=filesystem, binary.data.data is a small placeholder
// reference (~13 chars), not the actual base64 content. The real bytes live on
// the filesystem behind binary.data.id and must be loaded via the helper.
// Without this fix, every TTS response decoded as 9 bytes of garbage → empty
// silent placeholder WAVs across the entire lesson.
let pcm = null;
if (binaryData) {
  try {
    pcm = await this.helpers.getBinaryDataBuffer(0, 'data');
    failureDiag.pcmBytes = pcm?.length || 0;
    if (pcm && pcm.length > 0 && pcm.length < 500) {
      // Only preview small buffers — large valid TTS audio doesn't need a preview
      failureDiag.contentPreview = pcm.toString('utf8', 0, Math.min(200, pcm.length));
    }
  } catch (e) {
    failureDiag.bufferLoadError = e.message;
    console.error(`getBinaryDataBuffer failed for ${segment_id}_${lang}: ${e.message}`);
  }
}

// Failure threshold: anything shorter than 100ms of PCM (4410 bytes at 22050Hz
// mono 16-bit) is treated as a failed TTS response.
const MIN_VALID_PCM_BYTES = 4410;  // 0.1s × 22050 × 2
if (pcm && pcm.length < MIN_VALID_PCM_BYTES) {
  console.error(`TTS response too small for ${segment_id}_${lang}: ${pcm.length} bytes. Preview: ${JSON.stringify(failureDiag.contentPreview)}`);
  pcm = null;
}
let text = job.text;
let initialTtsFailed = !pcm;
if (initialTtsFailed && !binaryData) console.error(`Initial ElevenLabs TTS produced no binary at all for ${segment_id}_${lang} — likely HTTP error swallowed by onError.`);

function pcmDuration(buf) { return buf.length / (SAMPLE_RATE * BPS); }

function buildWav(pcmBuf) {
  const n = pcmBuf.length;
  const h = Buffer.alloc(44);
  h.write('RIFF', 0);          h.writeUInt32LE(36 + n, 4);
  h.write('WAVE', 8);          h.write('fmt ', 12);
  h.writeUInt32LE(16, 16);     h.writeUInt16LE(1, 20);
  h.writeUInt16LE(1, 22);      h.writeUInt32LE(SAMPLE_RATE, 24);
  h.writeUInt32LE(SAMPLE_RATE * BPS, 28);
  h.writeUInt16LE(BPS, 32);    h.writeUInt16LE(16, 34);
  h.write('data', 36);         h.writeUInt32LE(n, 40);
  return Buffer.concat([h, pcmBuf]);
}

async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
async function tts(t, speed) {
  // Soft-fail: returns null on final failure instead of throwing. Caller checks for null and
  // either keeps the previous PCM (for retries inside Check Timing) or builds a silent WAV
  // with needs_attention=true (for initial TTS). Prevents one bad segment from killing W3
  // and triggering an expensive full-workflow retry.
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.elevenlabs.io/v1/text-to-speech/${voice_id}?output_format=pcm_22050`,
        headers: { 'xi-api-key': EL_KEY, 'content-type': 'application/json' },
        body: { text: t, model_id: 'eleven_multilingual_v2', voice_settings: { stability, similarity_boost, speed } },
        json: true, returnFullResponse: true, encoding: 'arraybuffer',
      });
      return Buffer.from(resp.body);
    } catch (e) {
      const isLast = attempt === MAX_TRIES - 1;
      if (isLast) {
        console.error(`tts() failed for ${segment_id}_${lang} after ${MAX_TRIES} tries:`, e.message);
        return null;
      }
      // Exponential backoff: 2s, 4s, 8s.
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return null;
}

// Strip Claude meta-commentary.
// Meditation translations are always single-line; cut at FIRST newline — anything after is meta
// like "(Already at N characters; cannot shorten further)" which Claude sometimes appends.
function sanitizeClaudeOutput(rawText) {
  if (!rawText) return '';
  let t = rawText.trim();
  const nlIdx = t.indexOf('\n');
  if (nlIdx >= 0) t = t.substring(0, nlIdx).trim();
  // Strip leading/trailing markdown emphasis (*, **, __)
  t = t.replace(/^[\*_]+|[\*_]+$/g, '').trim();
  // Strip surrounding quotes
  t = t.replace(/^["'`]+|["'`]+$/g, '').trim();
  // Strip trailing parenthesized meta even on same line ("text (12 chars)")
  t = t.replace(/\s*\([^)]*(character|char|cannot|already|maximally|minimal)[^)]*\)\s*$/i, '').trim();
  return t;
}

async function callClaude(systemBlocks, userText) {
  const MAX_TRIES = 4;
  for (let attempt = 0; attempt < MAX_TRIES; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.anthropic.com/v1/messages',
        headers: { 'x-api-key': ANT_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body: { model: HAIKU_MODEL, max_tokens: 500, system: systemBlocks, messages: [{ role: 'user', content: userText }] },
        json: true,
      });
      return resp.content?.[0]?.text?.trim() || '';
    } catch (e) {
      const isLast = attempt === MAX_TRIES - 1;
      if (isLast) { console.error('W3 callClaude failed after retries:', e.message); return ''; }
      // Exponential backoff: 2s, 4s, 8s.
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

const SHORTEN_STATIC = loadPrompt('w3_shorten_system', { tov: TOV });

async function claudeShorten(currentText, realSec, level) {
  const minChars       = Math.floor(currentText.length * MIN_RETAIN);
  const targetChars    = Math.floor(slot * (LANG_CPS[lang] || 15));
  const targetCharsLow = Math.floor(targetChars * 0.85);
  const floorChars     = Math.max(minChars, targetCharsLow);

  const dynamicPart = `Task — shorten this segment:
LANG: ${lang}
ORIGINAL EN: ${enRef}
CURRENT TRANSLATION: ${currentText}
TARGET LENGTH: ~${targetChars} characters
MINIMUM ALLOWED LENGTH: ${floorChars} characters — do NOT go below this
ATTEMPT LEVEL: ${level}`;

  const systemBlocks = [
    { type: 'text', text: SHORTEN_STATIC, cache_control: { type: 'ephemeral' } },
    { type: 'text', text: dynamicPart },
  ];
  const raw = await callClaude.call(this, systemBlocks, currentText);
  const result = sanitizeClaudeOutput(raw);
  if (!result || result.length < floorChars) return currentText;
  return result;
}


if (!enDur || enDur <= 0) {
  const leadBytes   = Math.round(naturalLead * SAMPLE_RATE) * BPS;
  const leadSilence = leadBytes > 0 ? Buffer.alloc(leadBytes, 0) : Buffer.alloc(0);
  const wav         = buildWav(Buffer.concat([leadSilence, pcm]));
  const realSec     = pcmDuration(pcm);
  const fileName    = `${segment_id}_${lang}.wav`;
  return [{
    json: { segment_id, lang, lesson_id, en_duration_sec: 0,
            lead_silence_sec:              naturalLead,
            tts_budget_sec:                0,
            tail_silence_sec:              0,
            borrowed_sec:                  0,
            expansion_attempts:            0,
            shorten_retries_in_synthesize: 0,
            real_duration_sec:             parseFloat(realSec.toFixed(3)),
            final_duration_sec:            parseFloat((naturalLead + realSec).toFixed(3)),
            final_text:                    text,
            final_speed: 1.0, needs_attention: true, file_name: fileName,
            warning: 'en_duration_sec missing — file not strictly timed' },
    binary: { data: { data: wav.toString('base64'), mimeType: 'audio/wav', fileName } }
  }];
}

let finalSpeed        = parseFloat(job.speed) || 1.0;
let needsAttention    = false;
let shortenRetries    = 0;
let expansionAttempts = 0;

// Soft fallback: if initial TTS produced no audio, emit a silent placeholder WAV of
// en_duration length so downstream Save to Drive / Build Full Audio Per Lang still run.
// W3 finishes successfully; W_Master Slack notification still fires; flag for manual
// review via needs_attention=true.
if (!pcm) {
  const silentBytes = Math.round(enDur * SAMPLE_RATE) * BPS;
  const silentPcm   = silentBytes > 0 ? Buffer.alloc(silentBytes, 0) : Buffer.alloc(0);
  const wav         = buildWav(silentPcm);
  const fileName    = `${segment_id}_${lang}.wav`;
  return [{
    json: { segment_id, lang, lesson_id,
            en_duration_sec:               enDur,
            lead_silence_sec:              0,
            tts_budget_sec:                0,
            tail_silence_sec:              0,
            borrowed_sec:                  0,
            expansion_attempts:            0,
            shorten_retries_in_synthesize: 0,
            real_duration_sec:             0,
            final_duration_sec:            parseFloat((silentBytes / (SAMPLE_RATE * BPS)).toFixed(3)),
            final_text:                    text,
            final_speed:                   1.0,
            needs_attention:               true,
            file_name:                     fileName,
            warning:                       'ElevenLabs TTS failed — diag: ' + JSON.stringify(failureDiag) },
    binary: { data: { data: wav.toString('base64'), mimeType: 'audio/wav', fileName } }
  }];
}

const LEVELS = ['light', 'medium', 'max'];
for (let i = 0; i < 3 && pcmDuration(pcm) > maxAllowed; i++) {
  const realSec = pcmDuration(pcm);
  const shorter = await claudeShorten.call(this, text, realSec, LEVELS[i]);
  if (shorter && shorter !== text) {
    const newPcm = await tts.call(this, shorter, 1.0);
    if (newPcm) {
      text = shorter;
      pcm  = newPcm;
    } else {
      // TTS failed during shorten retry — keep previous text/pcm, abort shorten loop.
      needsAttention = true;
      shortenRetries = i + 1;
      break;
    }
  }
  shortenRetries = i + 1;
}

for (const speed of [1.10, 1.15]) {
  if (pcmDuration(pcm) <= maxAllowed) break;
  const newPcm = await tts.call(this, text, speed);
  if (!newPcm) {
    // TTS failed during speed retry — keep previous pcm + finalSpeed, abort loop.
    needsAttention = true;
    break;
  }
  pcm = newPcm;
  finalSpeed = speed;
}

if (pcmDuration(pcm) > maxAllowed) {
  needsAttention = true;
  const truncBytes = Math.round(maxAllowed * SAMPLE_RATE) * BPS;
  pcm = pcm.subarray(0, truncBytes);
}

// Inline expansion removed — Phase 2 batch handles all expansion candidates.

const realDur = pcmDuration(pcm);
let leadSec, tailSec, borrowedSec;

if (realDur <= enDur) {
  const padding = enDur - realDur;
  borrowedSec = 0;
  if (naturalLead > 0) {
    leadSec = naturalLead;
    tailSec = padding;
  } else {
    // Cap breath-lead so dubbed words align with EN even when EN slot has a long trailing silence
    leadSec = Math.min(padding * leadRatio, leadMaxSec);
    tailSec = padding - leadSec;
  }
} else if (realDur <= maxAllowed) {
  // Borrow case (short-seg path): TTS audio extends past en_duration into the trailing
  // silence budgeted in effective_slot_sec. File duration = lead + real_dur, no tail.
  // borrowed_sec = how much we extended beyond en_duration. Not flagged for attention —
  // this is intentional breath-borrow for ultra-short segments.
  borrowedSec = parseFloat((realDur - enDur).toFixed(3));
  leadSec     = naturalLead;
  tailSec     = 0;
} else {
  // Defensive: real_dur exceeds even the borrow ceiling. Hard-truncate earlier in the
  // shorten/speed loop should have prevented this; flag for manual review if reached.
  borrowedSec = parseFloat((maxAllowed - enDur).toFixed(3));
  leadSec     = naturalLead;
  tailSec     = 0;
  needsAttention = true;
}

const leadBytes = Math.round(leadSec * SAMPLE_RATE) * BPS;
const tailBytes = Math.round(tailSec * SAMPLE_RATE) * BPS;
const finalPcm  = Buffer.concat([
  leadBytes > 0 ? Buffer.alloc(leadBytes, 0) : Buffer.alloc(0),
  pcm,
  tailBytes > 0 ? Buffer.alloc(tailBytes, 0) : Buffer.alloc(0),
]);

const wav           = buildWav(finalPcm);
const finalDuration = (leadBytes + pcm.length + tailBytes) / (SAMPLE_RATE * BPS);
const fileName      = `${segment_id}_${lang}.wav`;

return [{
  json: {
    segment_id, lang, lesson_id,
    en_duration_sec:               enDur,
    lead_silence_sec:              parseFloat(leadSec.toFixed(3)),
    tts_budget_sec:                parseFloat(budget.toFixed(3)),
    tail_silence_sec:              parseFloat(tailSec.toFixed(3)),
    borrowed_sec:                  parseFloat(borrowedSec.toFixed(3)),
    expansion_attempts:            expansionAttempts,
    shorten_retries_in_synthesize: shortenRetries,
    real_duration_sec:             parseFloat(realDur.toFixed(3)),
    final_duration_sec:            parseFloat(finalDuration.toFixed(3)),
    final_text:                    text,
    final_speed:                   finalSpeed,
    needs_attention:               needsAttention,
    file_name:                     fileName,
  },
  binary: { data: { data: wav.toString('base64'), mimeType: 'audio/wav', fileName } }
}];

// Iterate over Drive Save responses (one per uploaded WAV in this batch) and JOIN with
// Check Timing + Pad + Expand TTS Jobs by file_name. Item-pairing accessors (.item) break
// when Loop Over Items uses batchSize > 1, so JOIN by file_name is more robust.
const checkAll = $('Check Timing + Pad').all();
const jobAll = $('Expand TTS Jobs').all();
const out = [];
for (const driveItem of $input.all()) {
  const driveResp = driveItem.json || {};
  const fileName = driveResp.name || '';
  if (!fileName) { console.warn('Save to Drive response missing name; skipping'); continue; }

  const checkEntry = checkAll.find(c => c.json && c.json.file_name === fileName);
  if (!checkEntry) { console.warn('No Check Timing + Pad entry for', fileName); continue; }
  const checkItem = checkEntry.json;
  const jobEntry = jobAll.find(j => j.json && j.json.segment_id === checkItem.segment_id && j.json.lang === checkItem.lang);
  const job = jobEntry ? jobEntry.json : {};

  out.push({
    json: {
      row_key:                       `${checkItem.segment_id}_${checkItem.lang}`,
      segment_id:                    checkItem.segment_id,
      lang:                          checkItem.lang,
      text_translated:               checkItem.final_text || job.text || '',
      en_start_sec:                  job.en_start_sec,
      en_duration_sec:               checkItem.en_duration_sec,
      slot_start_sec:                job.slot_start_sec,
      slot_end_sec:                  job.slot_end_sec,
      lead_silence_sec:              checkItem.lead_silence_sec,
      tts_budget_sec:                checkItem.tts_budget_sec,
      tail_silence_sec:              checkItem.tail_silence_sec,
      borrowed_sec:                  checkItem.borrowed_sec,
      expansion_attempts:            checkItem.expansion_attempts,
      shorten_retries_in_synthesize: checkItem.shorten_retries_in_synthesize,
      real_duration_sec:             checkItem.real_duration_sec,
      final_duration_sec:            checkItem.final_duration_sec,
      final_speed:                   checkItem.final_speed,
      needs_attention:               checkItem.needs_attention ? 'TRUE' : 'FALSE',
      audio_drive_file_id:           driveResp.id || '',
    },
  });
}
return out;

// Concat per-segment WAVs into one full WAV per language.
// Memory-conscious: iterates active_langs sequentially, no pre-grouping of all items,
// explicit reference cleanup after each lang. Pairs with N8N_BINARY_DATA_MODE=filesystem
// for further heap savings.
const SAMPLE_RATE = 22050;
const BPS         = 2;

const lesson_id = $('Get Params').first().json.lesson_id;

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const activeLangs = (configMap.active_langs || 'de,es,fr,it,pl,pt,tr')
  .split(',').map(s => s.trim()).filter(Boolean).sort();

const items = $input.all();
if (!items.length) throw new Error('No items — Download Segment WAV must run first');

// Map item reference → its original index in $input.all() so that, after
// filter/sort, we can still pass the correct itemIndex to getBinaryDataBuffer.
// (Critical for N8N_BINARY_DATA_MODE=filesystem support — see Check Timing + Pad.)
const indexMap = new Map(items.map((it, idx) => [it, idx]));

const results = [];
for (const lang of activeLangs) {
  // Lazy filter for current lang only (no pre-grouping → no doubled refs).
  const entries = items
    .filter(i => i.json && i.json.lang === lang)
    .filter(i => !lesson_id || (i.json.segment_id || '').startsWith(lesson_id + '_'))
    .sort((a, b) => String(a.json.segment_id).localeCompare(String(b.json.segment_id)));

  if (!entries.length) continue;

  // Strip 44-byte WAV header from each segment, accumulate raw PCM.
  //
  // BORROW COMPENSATION (drift fix):
  // When segment N has borrowed_sec > 0, its WAV extends past en_end[N] by that amount
  // (breath-borrow path in Check Timing + Pad). To keep the concatenated lesson aligned
  // with the EN timeline we trim that many seconds from the START of seg N+1's PCM —
  // eating into its lead silence, never into TTS audio. The borrow budget in Expand
  // TTS Jobs (max_borrowable ≤ gap_after − MIN_GAP, and lead_silence[N+1] == gap_after[N])
  // guarantees trimSec ≤ lead_silence[N+1], so the bound is structural; the
  // Math.min(prevBorrow, leadSec) clamp is belt-and-braces in case Sheet round-trip
  // introduces rounding.
  const pcmChunks = [];
  let prevBorrow      = 0;
  let trimmedLeadSum  = 0;
  let skippedNoBinary = 0;
  let skippedEmptyWav = 0;
  for (const e of entries) {
    if (!e.binary?.data) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — no binary slot on item`);
      continue;
    }
    // CRITICAL: must use this.helpers.getBinaryDataBuffer() — see Check Timing
    // + Pad for full explanation. With N8N_BINARY_DATA_MODE=filesystem the raw
    // binary.data.data is a tiny placeholder, not the actual WAV bytes.
    const originalIdx = indexMap.get(e);
    if (originalIdx === undefined) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — could not resolve original item index`);
      continue;
    }
    let wavBuf;
    try {
      wavBuf = await this.helpers.getBinaryDataBuffer(originalIdx, 'data');
    } catch (err) {
      skippedNoBinary++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — getBinaryDataBuffer failed: ${err.message}`);
      continue;
    }
    if (!wavBuf || wavBuf.length <= 44) {
      skippedEmptyWav++;
      console.warn(`Build Full: ${lang} ${e.json?.segment_id} skipped — WAV is ${wavBuf?.length ?? 0} bytes (header-only or empty)`);
      continue;
    }
    let pcm = wavBuf.subarray(44);
    if (prevBorrow > 0) {
      const leadSec   = parseFloat(e.json.lead_silence_sec) || 0;
      const trimSec   = Math.min(prevBorrow, leadSec);
      const trimBytes = Math.round(trimSec * SAMPLE_RATE) * BPS;
      if (trimBytes > 0 && trimBytes < pcm.length) {
        pcm = pcm.subarray(trimBytes);
        trimmedLeadSum += trimSec;
      }
    }
    pcmChunks.push(pcm);
    prevBorrow = parseFloat(e.json.borrowed_sec) || 0;
  }

  const fullPcm = Buffer.concat(pcmChunks);
  pcmChunks.length = 0;  // explicit ref clear — helps GC reclaim per-segment buffers
  const n = fullPcm.length;

  // Build fresh WAV header (22050Hz mono 16-bit — matches segments)
  const h = Buffer.alloc(44);
  h.write('RIFF', 0);          h.writeUInt32LE(36 + n, 4);
  h.write('WAVE', 8);          h.write('fmt ', 12);
  h.writeUInt32LE(16, 16);     h.writeUInt16LE(1, 20);
  h.writeUInt16LE(1, 22);      h.writeUInt32LE(SAMPLE_RATE, 24);
  h.writeUInt32LE(SAMPLE_RATE * BPS, 28);
  h.writeUInt16LE(BPS, 32);    h.writeUInt16LE(16, 34);
  h.write('data', 36);         h.writeUInt32LE(n, 40);
  const fullWav = Buffer.concat([h, fullPcm]);

  const lessonId = String(entries[0].json.segment_id).split('_seg_')[0] || 'lesson';
  const fileName = `${lessonId}_full_${lang}.wav`;

  if (skippedNoBinary > 0 || skippedEmptyWav > 0) {
    console.warn(`Build Full: ${lang} skipped ${skippedNoBinary} items (no binary) + ${skippedEmptyWav} items (empty WAV) out of ${entries.length}`);
  }
  results.push({
    json: {
      lang,
      lesson_id:              lessonId,
      file_name:              fileName,
      total_segments:         entries.length,
      skipped_no_binary:      skippedNoBinary,
      skipped_empty_wav:      skippedEmptyWav,
      full_duration_sec:      parseFloat((n / (SAMPLE_RATE * BPS)).toFixed(3)),
      trimmed_lead_total_sec: parseFloat(trimmedLeadSum.toFixed(3)),
    },
    binary: {
      data: {
        data:     fullWav.toString('base64'),
        mimeType: 'audio/wav',
        fileName,
      },
    },
  });
  // fullPcm + fullWav fall out of scope at next iteration — GC can reclaim.
}

if (!results.length) throw new Error('No localizations to concat' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));
return results;

// Build WebVTT subtitles per active language. One .vtt per lang, matching the
// full-lesson WAV positions. Runs in parallel with Download Segment WAV (both read
// the same Read Localizations Fresh output).
//
// Cue timings: en_start_sec → en_end_sec. After the borrow-compensation fix in
// Build Full Audio Per Lang, each segment in the full WAV starts exactly at
// en_start_sec — so EN-aligned cues match the dubbed audio for every language.
// Cue text: text_translated (final version after Verify + Adapt + W3 shorten).
const lesson_id = $('Get Params').first().json.lesson_id;

const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });
const activeLangs = (configMap.active_langs || 'de,es,fr,it,pl,pt,tr')
  .split(',').map(s => s.trim()).filter(Boolean);

const items = $input.all();
if (!items.length) throw new Error('No items — Read Localizations Fresh must run first');

function fmtTime(sec) {
  // VTT timestamp: HH:MM:SS.mmm
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = sec - h * 3600 - m * 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${s.toFixed(3).padStart(6, '0')}`;
}

const results = [];
for (const lang of activeLangs) {
  const segs = items
    .filter(i => i.json && i.json.lang === lang)
    .filter(i => !lesson_id || (i.json.segment_id || '').startsWith(lesson_id + '_'))
    .sort((a, b) => String(a.json.segment_id).localeCompare(String(b.json.segment_id)));
  if (!segs.length) continue;

  const lines = ['WEBVTT', ''];
  let cueIdx = 0;
  for (const e of segs) {
    const s = e.json;
    const start = parseFloat(s.en_start_sec) || 0;
    const dur   = parseFloat(s.en_duration_sec) || 0;
    const end   = start + dur;
    const text  = (s.text_translated || '').toString().trim().replace(/\r?\n/g, ' ');
    if (!text) continue;
    cueIdx++;
    lines.push(String(cueIdx));
    lines.push(`${fmtTime(start)} --> ${fmtTime(end)}`);
    lines.push(text);
    lines.push('');
  }
  if (cueIdx === 0) continue;
  const vtt = lines.join('\n');

  const lessonId = String(segs[0].json.segment_id).split('_seg_')[0] || 'lesson';
  const fileName = `${lessonId}_full_${lang}.vtt`;
  results.push({
    json: {
      lang,
      lesson_id: lessonId,
      file_name: fileName,
      total_cues: cueIdx,
      vtt_bytes:  Buffer.byteLength(vtt, 'utf8'),
    },
    binary: {
      data: {
        data: Buffer.from(vtt, 'utf8').toString('base64'),
        mimeType: 'text/vtt',
        fileName,
      },
    },
  });
}

if (!results.length) throw new Error('No localizations for VTT' + (lesson_id ? ' for lesson_id=' + lesson_id : ''));
return results;

// W3 Phase 2: Batched late-stage expansion through Verify + Editor.
// Reads all localizations rows from Read Localizations Fresh, identifies cells with
// real_duration < en_duration × threshold (and needs_attention=false), runs a batch
// Expansion (Anthropic Sonnet) → Verify (Sonnet QA) → Editor (Gemini Flash) → re-TTS
// pipeline. For each accepted expansion, builds a new WAV (same lead silence + new TTS +
// recomputed tail silence) and emits an item with new binary + updated metadata for
// downstream Drive Update (overwrites file at same audio_drive_file_id) and Update
// Localizations Sheet nodes. Items where expansion was rejected or not needed are NOT
// emitted (this branch terminates side-effect only; Download Segment WAV continues
// reading the original Read Localizations Fresh items in parallel branch).

const SAMPLE_RATE = 22050;
const BPS = 2;
const EXPAND_BATCH_SIZE = 8;
const CHUNK = 6;                 // Tier 2 Anthropic — higher parallelism than W2's CHUNK=3
const ELEVENLABS_CHUNK = 5;      // parallel TTS calls per slice
const MAX_RETAIN_EXPANSION = 1.5;
const ANTHROPIC_URL = 'https://api.anthropic.com/v1/messages';
const GEMINI_URL = 'https://generativelanguage.googleapis.com/v1beta/openai/chat/completions';
const ELEVENLABS_URL = (vid) => `https://api.elevenlabs.io/v1/text-to-speech/${vid}/stream?output_format=pcm_22050`;

// --- read config + prompts + voices ---
const configMap = {};
$('Read Config').all().forEach(i => { if (i.json.key) configMap[i.json.key] = i.json.value; });

const promptMap = {};
$('Read Prompts').all().forEach(i => { if (i.json.key) promptMap[i.json.key] = i.json.value; });

const voiceMap = {};
$('Read Voices').all().forEach(i => { if (i.json.lang) voiceMap[i.json.lang] = i.json; });

const THRESHOLD = parseFloat(configMap.expansion_threshold) || 0.85;
const apiKey = configMap.anthropic_api_key || '';
const geminiKey = configMap.gemini_api_key || '';
const elevenKey = configMap.elevenlabs_api_key || '';
if (!apiKey || !geminiKey || !elevenKey) {
  throw new Error('Phase 2: missing API key in config (anthropic_api_key/gemini_api_key/elevenlabs_api_key)');
}

function loadPrompt(key, vars = {}) {
  const raw = promptMap[key];
  if (!raw) throw new Error(`Missing prompt "${key}" in prompts sheet — add a row with this key`);
  const result = Object.entries(vars).reduce(
    (s, [k, v]) => s.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), String(v ?? '')),
    raw
  );
  const leaks = result.match(/\{\{\s*[a-z][a-z0-9_]*\s*\}\}/g);
  if (leaks) throw new Error(`Unsubstituted placeholders in prompt "${key}": ${leaks.join(', ')}`);
  return result;
}

const TOV = loadPrompt('tone_of_voice');
const EXPAND_BATCH_SYSTEM = loadPrompt('w3_expand_batch_system', { tov: TOV });
const QA_SYSTEM = loadPrompt('qa_verify_system');
const EDITOR_SYSTEM = loadPrompt('editor_system');

const CPS_DEFAULTS = { de: 12, es: 15, fr: 15, pl: 14, pt: 16, it: 14, tr: 14 };
const LANG_CPS = {};
for (const l of ['de','es','fr','pl','pt','it','tr']) {
  LANG_CPS[l] = parseFloat(configMap['cps_estimate_' + l]) || CPS_DEFAULTS[l];
}

// --- collect candidates ---
const allItems = $input.all();
const candidates = {};  // { segment_id: { en, langs: { [lang]: { current, real, en_dur, lead, file_id, row_key, lesson_id, voice_id, voice_speed, ... } } } }
for (const it of allItems) {
  const j = it.json;
  // Skip needs_attention rows (Phase 1 already flagged for manual review)
  if (j.needs_attention === true || j.needs_attention === 'TRUE' || j.needs_attention === 'true') continue;
  const enDur = parseFloat(j.en_duration_sec) || 0;
  const real = parseFloat(j.real_duration_sec) || 0;
  if (enDur <= 0 || real <= 0) continue;
  if (real >= enDur * THRESHOLD) continue;

  const lang = j.lang;
  const voice = voiceMap[lang];
  if (!voice || !voice.voice_id) continue;

  if (!candidates[j.segment_id]) {
    candidates[j.segment_id] = { en: j.en_text || '', langs: {} };
  }
  candidates[j.segment_id].langs[lang] = {
    current: j.text_translated || '',
    real_duration: real,
    en_duration: enDur,
    lead_silence: parseFloat(j.lead_silence_sec) || 0,
    audio_drive_file_id: j.audio_drive_file_id,
    row_key: j.row_key,
    segment_id: j.segment_id,
    lesson_id: j.lesson_id || (j.segment_id || '').split('_seg_')[0],
    lang,
    voice_id: voice.voice_id,
    voice_speed: parseFloat(voice.speed) || 1.0,
    voice_model: voice.model || 'eleven_multilingual_v2',
    voice_stability: parseFloat(voice.stability) || 0.5,
    voice_similarity: parseFloat(voice.similarity_boost) || 0.75,
    voice_style: parseFloat(voice.style) || 0,
    en_start_sec: parseFloat(j.en_start_sec) || 0,
    slot_start_sec: parseFloat(j.slot_start_sec) || 0,
    slot_end_sec: parseFloat(j.slot_end_sec) || 0,
    tts_budget_sec: parseFloat(j.tts_budget_sec) || enDur,
  };
}

const totalSegments = Object.keys(candidates).length;
let totalCells = 0;
for (const data of Object.values(candidates)) totalCells += Object.keys(data.langs).length;

if (totalSegments === 0) {
  console.log('Phase 2: no expansion candidates — branch terminates with 0 items');
  return [];
}
console.log(`Phase 2: ${totalSegments} segments / ${totalCells} cells to expand`);

// --- HTTP helpers ---
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function callAnthropic(body, retries = 3) {
  for (let attempt = 0; attempt < retries; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: ANTHROPIC_URL,
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
        body, json: true,
      });
      return resp.content?.[0]?.text?.trim() || '';
    } catch (e) {
      if (attempt === retries - 1) { console.error('Phase 2 Anthropic failed:', e.message); return ''; }
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

async function callGemini(body, retries = 3) {
  for (let attempt = 0; attempt < retries; attempt++) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: GEMINI_URL,
        headers: { Authorization: `Bearer ${geminiKey}`, 'content-type': 'application/json' },
        body, json: true,
      });
      return resp.choices?.[0]?.message?.content?.trim() || '';
    } catch (e) {
      if (attempt === retries - 1) { console.error('Phase 2 Gemini failed:', e.message); return ''; }
      await sleep(2000 * Math.pow(2, attempt));
    }
  }
  return '';
}

function parseLLMJson(raw) {
  try {
    const cleaned = (raw || '').replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
  } catch (e) {
    console.error('Phase 2 parseLLMJson error:', e.message);
  }
  return {};
}

// --- group into batches of EXPAND_BATCH_SIZE segments ---
const segmentEntries = Object.entries(candidates);
const expandBatches = [];
for (let i = 0; i < segmentEntries.length; i += EXPAND_BATCH_SIZE) {
  expandBatches.push(segmentEntries.slice(i, i + EXPAND_BATCH_SIZE));
}
console.log(`Phase 2: ${expandBatches.length} batches of up to ${EXPAND_BATCH_SIZE} segments each`);

// --- Phase 2.1: BATCH EXPAND ---
async function runOneExpandBatch(batch) {
  const userMap = {};
  for (const [sid, data] of batch) {
    userMap[sid] = { en: data.en };
    for (const [lang, info] of Object.entries(data.langs)) {
      const targetChars = Math.round(info.en_duration * (LANG_CPS[lang] || 15) * 0.95);
      userMap[sid][lang] = { current: info.current, target_chars: targetChars };
    }
  }
  const body = {
    model: 'claude-sonnet-4-5',
    max_tokens: 8000,
    system: [{ type: 'text', text: EXPAND_BATCH_SYSTEM, cache_control: { type: 'ephemeral' } }],
    messages: [{ role: 'user', content: JSON.stringify(userMap, null, 2) }],
  };
  const raw = await callAnthropic.call(this, body);
  return parseLLMJson(raw);
}

const expandedMap = {};
for (let i = 0; i < expandBatches.length; i += CHUNK) {
  const slice = expandBatches.slice(i, i + CHUNK);
  const partial = await Promise.all(slice.map(b => runOneExpandBatch.call(this, b)));
  for (const p of partial) Object.assign(expandedMap, p);
}
console.log(`Phase 2 expand complete — ${Object.keys(expandedMap).length} segments returned`);

// --- Phase 2.2: BATCH VERIFY (using expanded text) ---
async function runOneVerifyBatch(batch) {
  const userMap = {};
  for (const [sid, data] of batch) {
    if (!expandedMap[sid]) continue;
    userMap[sid] = { en: data.en };
    for (const lang of Object.keys(data.langs)) {
      const expanded = expandedMap[sid][lang];
      if (expanded && expanded.trim()) userMap[sid][lang] = expanded.trim();
    }
  }
  if (Object.keys(userMap).length === 0) return {};
  const body = {
    model: 'claude-sonnet-4-5',
    max_tokens: 8000,
    system: [{ type: 'text', text: QA_SYSTEM, cache_control: { type: 'ephemeral' } }],
    messages: [{ role: 'user', content: JSON.stringify(userMap, null, 2) }],
  };
  const raw = await callAnthropic.call(this, body);
  return parseLLMJson(raw);
}

const verifiedMap = {};
for (let i = 0; i < expandBatches.length; i += CHUNK) {
  const slice = expandBatches.slice(i, i + CHUNK);
  const partial = await Promise.all(slice.map(b => runOneVerifyBatch.call(this, b)));
  for (const p of partial) Object.assign(verifiedMap, p);
}

// Apply verify corrections: if verify returned text for (sid, lang), use it; else keep expanded
const postVerifyMap = {};
for (const [sid, data] of segmentEntries) {
  const expanded = expandedMap[sid];
  if (!expanded) continue;
  postVerifyMap[sid] = {};
  for (const lang of Object.keys(data.langs)) {
    const expText = expanded[lang];
    if (!expText || !expText.trim()) continue;
    const verText = verifiedMap[sid]?.[lang];
    postVerifyMap[sid][lang] = (verText && verText.trim()) ? verText.trim() : expText.trim();
  }
}
console.log(`Phase 2 verify complete`);

// --- Phase 2.3: BATCH EDITOR ---
async function runOneEditorBatch(batch) {
  const userMap = {};
  for (const [sid, data] of batch) {
    if (!postVerifyMap[sid]) continue;
    userMap[sid] = { en: data.en };
    for (const lang of Object.keys(data.langs)) {
      const text = postVerifyMap[sid][lang];
      if (text) userMap[sid][lang] = text;
    }
  }
  if (Object.keys(userMap).length === 0) return {};
  const body = {
    model: 'gemini-3.5-flash',
    messages: [
      { role: 'system', content: EDITOR_SYSTEM },
      { role: 'user', content: JSON.stringify(userMap, null, 2) },
    ],
    response_format: { type: 'json_object' },
  };
  const raw = await callGemini.call(this, body);
  return parseLLMJson(raw);
}

const editedMap = {};
for (let i = 0; i < expandBatches.length; i += CHUNK) {
  const slice = expandBatches.slice(i, i + CHUNK);
  const partial = await Promise.all(slice.map(b => runOneEditorBatch.call(this, b)));
  for (const p of partial) Object.assign(editedMap, p);
}

// Final text per (sid, lang) — prefer editor > verify > expanded
const finalTextMap = {};
for (const [sid, data] of segmentEntries) {
  if (!postVerifyMap[sid]) continue;
  finalTextMap[sid] = {};
  for (const lang of Object.keys(data.langs)) {
    const postVerify = postVerifyMap[sid][lang];
    if (!postVerify) continue;
    const edited = editedMap[sid]?.[lang];
    finalTextMap[sid][lang] = (edited && edited.trim()) ? edited.trim() : postVerify;
  }
}
console.log(`Phase 2 editor complete`);

// --- Phase 2.4: RE-TTS + WAV rebuild ---
function buildWav(pcm) {
  const n = pcm.length;
  const h = Buffer.alloc(44);
  h.write('RIFF', 0); h.writeUInt32LE(36 + n, 4); h.write('WAVE', 8); h.write('fmt ', 12);
  h.writeUInt32LE(16, 16); h.writeUInt16LE(1, 20); h.writeUInt16LE(1, 22); h.writeUInt32LE(SAMPLE_RATE, 24);
  h.writeUInt32LE(SAMPLE_RATE * BPS, 28); h.writeUInt16LE(BPS, 32); h.writeUInt16LE(16, 34);
  h.write('data', 36); h.writeUInt32LE(n, 40);
  return Buffer.concat([h, pcm]);
}

async function reTtsOne(task) {
  const { sid, lang, newText, info } = task;
  if (!newText || newText.trim() === info.current.trim()) {
    return { sid, lang, skipped: 'no_change' };
  }
  try {
    const ttsResp = await this.helpers.httpRequest({
      method: 'POST',
      url: ELEVENLABS_URL(info.voice_id),
      headers: { 'xi-api-key': elevenKey, 'content-type': 'application/json', accept: 'audio/pcm' },
      body: {
        text: newText,
        model_id: info.voice_model,
        voice_settings: {
          stability: info.voice_stability,
          similarity_boost: info.voice_similarity,
          style: info.voice_style,
          speed: info.voice_speed,
        },
      },
      encoding: 'arraybuffer',
      returnFullResponse: false,
    });
    const newPcm = Buffer.from(ttsResp);
    if (!newPcm || newPcm.length < 4410) {
      return { sid, lang, skipped: 'tts_too_short_or_empty', pcmLen: newPcm?.length || 0 };
    }
    const newRealDur = newPcm.length / (SAMPLE_RATE * BPS);

    // Overshoot guard: if new audio exceeds en_duration, abort — keep Phase 1 audio
    if (newRealDur > info.en_duration) {
      return { sid, lang, skipped: 'overshoot', newRealDur, enDuration: info.en_duration };
    }

    // Recompute padding: lead stays same (naturalLead invariant), tail shrinks
    const lead = info.lead_silence;
    let tail = info.en_duration - lead - newRealDur;
    if (tail < 0) {
      return { sid, lang, skipped: 'negative_tail', lead, newRealDur, enDur: info.en_duration };
    }
    const leadBytes = Math.round(lead * SAMPLE_RATE) * BPS;
    const tailBytes = Math.round(tail * SAMPLE_RATE) * BPS;
    const fullPcm = Buffer.concat([
      leadBytes > 0 ? Buffer.alloc(leadBytes, 0) : Buffer.alloc(0),
      newPcm,
      tailBytes > 0 ? Buffer.alloc(tailBytes, 0) : Buffer.alloc(0),
    ]);
    const newWav = buildWav(fullPcm);
    const finalDur = lead + newRealDur + tail;

    return {
      sid, lang, success: true,
      newText,
      newRealDur: parseFloat(newRealDur.toFixed(3)),
      newTailSilence: parseFloat(tail.toFixed(3)),
      newLeadSilence: parseFloat(lead.toFixed(3)),
      newFinalDur: parseFloat(finalDur.toFixed(3)),
      wavBase64: newWav.toString('base64'),
      info,
    };
  } catch (e) {
    return { sid, lang, error: e.message };
  }
}

// Build re-TTS task list (only cells where text actually changed)
const reTtsTasks = [];
for (const [sid, data] of segmentEntries) {
  if (!finalTextMap[sid]) continue;
  for (const [lang, info] of Object.entries(data.langs)) {
    const newText = finalTextMap[sid][lang];
    if (!newText) continue;
    if (newText.trim() === info.current.trim()) continue;
    reTtsTasks.push({ sid, lang, newText, info });
  }
}
console.log(`Phase 2: ${reTtsTasks.length} cells accepted for re-TTS (${totalCells - reTtsTasks.length} unchanged after LLM pipeline)`);

// Process re-TTS in CHUNK-parallel slices
const reTtsResults = [];
for (let i = 0; i < reTtsTasks.length; i += ELEVENLABS_CHUNK) {
  const slice = reTtsTasks.slice(i, i + ELEVENLABS_CHUNK);
  const partial = await Promise.all(slice.map(t => reTtsOne.call(this, t)));
  for (const r of partial) reTtsResults.push(r);
}

// Count outcomes
const accepted = reTtsResults.filter(r => r.success);
const skipped = reTtsResults.filter(r => r.skipped);
const errored = reTtsResults.filter(r => r.error);
console.log(`Phase 2 re-TTS results: accepted=${accepted.length}, skipped=${skipped.length}, errored=${errored.length}`);
if (skipped.length > 0) {
  const reasons = {};
  for (const s of skipped) reasons[s.skipped] = (reasons[s.skipped] || 0) + 1;
  console.log(`Phase 2 skip reasons:`, JSON.stringify(reasons));
}

// Emit per-(sid, lang) items for accepted expansions only
return accepted.map(r => ({
  json: {
    row_key:                       `${r.sid}_${r.lang}`,
    segment_id:                    r.sid,
    lang:                          r.lang,
    lesson_id:                     r.info.lesson_id,
    text_translated:               r.newText,
    en_start_sec:                  r.info.en_start_sec,
    en_duration_sec:               r.info.en_duration,
    real_duration_sec:             r.newRealDur,
    lead_silence_sec:              r.newLeadSilence,
    slot_start_sec:                r.info.slot_start_sec,
    slot_end_sec:                  r.info.slot_end_sec,
    tts_budget_sec:                r.info.tts_budget_sec,
    tail_silence_sec:              r.newTailSilence,
    final_duration_sec:            r.newFinalDur,
    borrowed_sec:                  0,
    expansion_attempts:            1,
    shorten_retries_in_synthesize: 0,
    final_speed:                   r.info.voice_speed,
    needs_attention:               false,
    audio_drive_file_id:           r.info.audio_drive_file_id,
    file_name:                     `${r.sid}_${r.lang}.wav`,
  },
  binary: {
    data: {
      data:     r.wavBase64,
      mimeType: 'audio/wav',
      fileName: `${r.sid}_${r.lang}.wav`,
    },
  },
}));
